  "ovningar1_053":{id:"ovningar1_053",namn:"Målvakt C - 9-12 år - Djupledsspel och frilägen –",typ:"Färdighetsövning",skede:"MV",kategori:"Målvakt – Djupledsspel & frilägen",principer:["Djupledsspel","Förhindra djupledsspel"],vad:"Förhindra och rädda avslut",varfor:"Hindra motståndarna att avsluta och göra mål.",hur:["Frågeexempel","Se Färdighetsträning 2-4 och Spelträning 1 i detta träningspass."],org:"10 barn, spelplan 25–35 x 15 m med 2 mål, bollar, koner och västar.",steg:["Lagen spelar 4 mot 4 i mittzonen.","Lagen gör mål genom att bollhållaren driver in bollen i anfallszonen och skapar ett friläge.","Motståndarna får inte följa med in i försvarszonen.","Efter några minuter byter lagen målvakt.","Ett alternativ är att bollen passas in i anfallszonen till en spelare som löper in efter bollen.","En motståndare får då följa med in och försvara."],prog:[],skiss:{layout:"mv_liten",dim:"35\u00d715m",spelare:[{x:8,y:50,roll:"MV"},{x:25,y:20,roll:"O"},{x:25,y:50,roll:"O"},{x:62,y:20,roll:"X"},{x:62,y:50,roll:"X"}],koner:[{x:10,y:10},{x:90,y:10},{x:10,y:90},{x:90,y:90}],pilar:[]},url:""},
  "ovningar1_054":{id:"ovningar1_054",namn:"Målvakt C - 12-14 år - Inlägg – fånga höga bollar (FÖ",typ:"Färdighetsövning",skede:"MV",kategori:"Målvakt – Inlägg",principer:["Inlägg & avslut","Förhindra avslut"],vad:"Förhindra och rädda avslut",varfor:"Förbereda kroppen för träning. Hindra motståndarna att avsluta.",hur:["Frågeexempel","Hur fångar du bollen så högt som möjligt?","Hur håller du händerna när du fångar bollen?"],org:"3 målvakter med var sin boll.",steg:["Spring med bollen i händerna och gör följande på tränarens kommando:"," Stanna och håll bollen så högt som möjligt"," Gör jämfota upphopp och håll bollen så högt som möjligt"," Gör upphopp på vänster eller höger ben och håll bollen så högt som möjligt"," Kasta upp bollen i luften. Hoppa upp jämfota eller på ett ben och fånga bollen."],prog:[],skiss:{layout:"mv_liten",dim:"",spelare:[{x:8,y:50,roll:"MV"},{x:25,y:20,roll:"O"},{x:25,y:50,roll:"O"},{x:62,y:20,roll:"X"},{x:62,y:50,roll:"X"}],koner:[{x:10,y:10},{x:90,y:10},{x:10,y:90},{x:90,y:90}],pilar:[]},url:""},
  "ovningar1_055":{id:"ovningar1_055",namn:"Målvakt C - 12-14 år - Inlägg – hoppa upp och fånga",typ:"Färdighetsövning",skede:"MV",kategori:"Målvakt – Explosivitet",principer:[],vad:"Förhindra och rädda avslut",varfor:"Komma före motståndaren och hindra avslut.",hur:["Träna att hoppa både jämfota och på ett ben.","Hur gör du för att komma upp så högt som möjligt?"],org:"3 målvakter, 2 mål avstånd 10–15 m och 2 bollar.",steg:["A och C har var sin boll.","A kastar bollen mot B som hoppar upp och fångar den.","B går till mål 1.","C kastar bollen mot A som hoppar upp och fångar den.","A går till mål 2.","Som en variant kan ni vinkla målen i förhållande till varandra."],prog:[],skiss:{layout:"mv_liten",dim:"",spelare:[{x:8,y:50,roll:"MV"},{x:25,y:20,roll:"O"},{x:25,y:50,roll:"O"},{x:62,y:20,roll:"X"},{x:62,y:50,roll:"X"}],koner:[{x:10,y:10},{x:90,y:10},{x:10,y:90},{x:90,y:90}],pilar:[]},url:""},
  "ovningar1_056":{id:"ovningar1_056",namn:"Målvakt C - 12-14 år - Inlägg – boxa bort bollen med",typ:"Färdighetsövning",skede:"MV",kategori:"Målvakt – Inlägg",principer:["Inlägg & avslut","Förhindra avslut"],vad:"Förhindra och rädda avslut",varfor:"Komma före motståndaren och hindra avslut.",hur:["Frågeexempel","Hur håller du händerna när du boxar?","Var träffar du bollen när du boxar och varför?"],org:"3 målvakter, 2 mål avstånd 10–15 m och bollar.",steg:["A kastar upp bollen i luften och boxar den till B.","A följer bollen.","B kastar upp bollen i luften och boxar den till C.","B följer bollen."],prog:[],skiss:{layout:"mv_liten",dim:"",spelare:[{x:8,y:50,roll:"MV"},{x:25,y:20,roll:"O"},{x:25,y:50,roll:"O"},{x:62,y:20,roll:"X"},{x:62,y:50,roll:"X"}],koner:[{x:10,y:10},{x:90,y:10},{x:10,y:90},{x:90,y:90}],pilar:[]},url:""},
  "ovningar1_057":{id:"ovningar1_057",namn:"Målvakt C - 12-14 år - Spelmomentträning - Inlägg –",typ:"Färdighetsövning",skede:"MV",kategori:"Målvakt – Inlägg",principer:["Inlägg & avslut","Förhindra avslut"],vad:"Förhindra och rädda avslut",varfor:"Hindra motståndaren att avsluta.",hur:["Frågeexempel","Var ska du ha din utgångsposition?","Hur gör du för att nå bollen före motståndaren?"],org:"3 målvakter, 2 mål avstånd 10–15 m och bollar.",steg:["A skjuter ett inlägg mot B.","B agerar målvakt samtidigt som C är motståndare.","A skjuter ett inlägg mot C.","C agerar målvakt samtidigt som B är motståndare.","Byt uppgifter efter några inlägg.","Inläggen kan ”spelas in” på olika sätt:  Kastas  Spelas in från marken  Spelas in på volley."],prog:[],skiss:{layout:"mv_liten",dim:"",spelare:[{x:8,y:50,roll:"MV"},{x:25,y:20,roll:"O"},{x:25,y:50,roll:"O"},{x:62,y:20,roll:"X"},{x:62,y:50,roll:"X"}],koner:[{x:10,y:10},{x:90,y:10},{x:10,y:90},{x:90,y:90}],pilar:[]},url:""},
  "ovningar1_058":{id:"ovningar1_058",namn:"Målvakt C - Koordination från 12 år, parövningar",typ:"Koordinationsövning",skede:"FYS",kategori:"Koordination",principer:["Koordination"],vad:"Fotbollskoordination",varfor:"Koordinationsträning tränar förmågan att samordna kroppsrörelser i förhållande till varandra och omgivningen. Anvisningar I dessa koordinationsövningar arbetar man i par och här behöver spelarna ha tillgång till var sin boll. A och B står mitt emot varandra. A har en boll. A böjer sig framåt och kastar bollen bakåt och uppåt mellan benen mot B. B fångar bollen och kastar till A på samma sätt. A driver en boll med fötterna, och B följer efter med en boll. På signal stannar de och byter boll med varandra. A rullar sin boll på marken och B kastar sin i luften. Byt uppgifter.",hur:[],org:"",steg:["I dessa koordinationsövningar arbetar man i par och här behöver spelarna ha tillgång till var sin boll.","A och B står mitt emot varandra. A har en boll.","A böjer sig framåt och kastar bollen bakåt och uppåt mellan benen mot B.","B fångar bollen och kastar till A på samma sätt.","A driver en boll med fötterna, och B följer efter med en boll. På signal stannar de och byter boll med varandra. A rullar sin boll på marken och B kastar sin i luften. Byt uppgifter."],prog:[],skiss:{layout:"mellan",dim:"",spelare:[{x:25,y:25,roll:"O",label:""},{x:25,y:50,roll:"O",label:""},{x:25,y:75,roll:"O",label:""},{x:65,y:25,roll:"X",label:""},{x:65,y:50,roll:"X",label:""},{x:65,y:75,roll:"X",label:""}],koner:[{x:15,y:15},{x:85,y:15},{x:15,y:85},{x:85,y:85}],pilar:[]},url:""},
  "ovningar1_059":{id:"ovningar1_059",namn:"Målvakt C - Koordination från 12 år, bollövningar 3",typ:"Koordinationsövning",skede:"FYS",kategori:"Koordination",principer:["Koordination"],vad:"Fotbollskoordination",varfor:"Koordinationsträning tränar förmågan att samordna kroppsrörelser i förhållande till varandra och omgivningen. Anvisningar Sitt på marken. Kasta upp bollen i luften. Res dig, spring efter bollen och fånga den innan den studsar. Kasta upp bollen i luften. Snurra ett varv och fånga bollen innan den studsar. Rulla bollen på marken eller kasta upp den i luften. Gör en kullerbytta och plocka upp eller fånga bollen.",hur:[],org:"",steg:["Sitt på marken. Kasta upp bollen i luften. Res dig, spring efter bollen och fånga den innan den studsar.","Kasta upp bollen i luften. Snurra ett varv och fånga bollen innan den studsar.","Rulla bollen på marken eller kasta upp den i luften. Gör en kullerbytta och plocka upp eller fånga bollen."],prog:[],skiss:{layout:"mellan",dim:"",spelare:[{x:25,y:25,roll:"O",label:""},{x:25,y:50,roll:"O",label:""},{x:25,y:75,roll:"O",label:""},{x:65,y:25,roll:"X",label:""},{x:65,y:50,roll:"X",label:""},{x:65,y:75,roll:"X",label:""}],koner:[{x:15,y:15},{x:85,y:15},{x:15,y:85},{x:85,y:85}],pilar:[]},url:""},
