  "ovningar2_039":{id:"ovningar2_039",namn:"Målvakt B - Hoppa upp och fånga bollen -",typ:"Färdighetsövning",skede:"MV",kategori:"Målvakt – Explosivitet",principer:[],vad:"Förhindra och rädda avslut",varfor:"Komma före motspelaren och förhindra avslut.",hur:["Frågeexempel","Vilket ben bör du göra avstampet med om du hoppar upp på ett ben?","Hur gör du för att hoppa så högt som möjligt?","Hur gör du för att få ett säkert grepp?"],org:"3 målvakter, 1 mål och bollar.",steg:["Mv1 kastar eller spelar bollen mot ytan vid främre stolpen.","Mv2 rör sig mot bollen, hoppar upp och fångar bollen.","Mv2 förflyttar sig tillbaka till sin utgångsposition.","Övningen upprepas med att Mv1 kastar eller spelar bollen mot två andra ytor – vid bortre stolpen och mellan målområdet och straffpunkten.","Upprepa med Mv3 som målvakt.","Byt uppgifter."],prog:[],skiss:{layout:"mv_liten",dim:"",spelare:[{x:8,y:50,roll:"MV"},{x:25,y:20,roll:"O"},{x:25,y:50,roll:"O"},{x:62,y:20,roll:"X"},{x:62,y:50,roll:"X"}],koner:[{x:10,y:10},{x:90,y:10},{x:10,y:90},{x:90,y:90}],pilar:[]},url:""},
  "ovningar2_040":{id:"ovningar2_040",namn:"Målvakt B - Uppvärmning - hoppa upp och fånga",typ:"Färdighetsövning",skede:"MV",kategori:"Målvakt – Explosivitet",principer:[],vad:"Förhindra och rädda avslut",varfor:"Förbereda kroppen för träning. Komma före motspelaren och förhindra avslut.",hur:["Frågeexempel","Vilket ben bör du göra avstampet med om du hoppar upp på ett ben?","Hur gör du för att hoppa så högt som möjligt?","Hur gör du för att fånga bollen så högt som möjligt?"],org:"3 målvakter, 2 mål, avstånd 15 meter, bollar och koner.",steg:["Mv1 kastar en hög boll mot kon 1.","Mv2 rör sig mot bollen, hoppar upp och fångar bollen.","Mv2 jobbar till mål 1.","Mv3 kastar en hög boll mot kon 1.","Mv1 rör sig mot bollen, hoppar upp och fångar bollen. Mv1 jobbar till mål 2.","Och så vidare."],prog:[],skiss:{layout:"mv_liten",dim:"",spelare:[{x:8,y:50,roll:"MV"},{x:25,y:20,roll:"O"},{x:25,y:50,roll:"O"},{x:62,y:20,roll:"X"},{x:62,y:50,roll:"X"}],koner:[{x:10,y:10},{x:90,y:10},{x:10,y:90},{x:90,y:90}],pilar:[]},url:""},
