  "ovningar2_042":{id:"ovningar2_042",namn:"Målvakt B - Spelmomentövning - Djupledsspel -",typ:"Färdighetsövning",skede:"MV",kategori:"Målvakt – Djupledsspel & frilägen",principer:["Djupledsspel","Förhindra djupledsspel"],vad:"Förhindra och rädda avslut",varfor:"Förhindra motståndarna att göra mål.",hur:["Frågeexempel","Hur gör du om motspelaren försöker dribbla förbi dig?","Hur gör du det svårt för motspelaren vid ett friläge?"],org:"2 målvakter, 12 utespelare, spelplan 40 x 35 meter med 2 mål, bollar, koner och västar.",steg:["X1 och X2 och O1 och O2 är fasta forwards. Mv1 kastar ut bollen till X1 som gör tillbakaspel till X3 eller X4.","X1, X2, X3 och X4 anfaller mot O3 och O4 och Mv2.","Efter avslutat anfall vilar X1, X2, O3 och O4.","Mv2 gör utkast till O1 som gör tillbakaspel till O5 eller O6.","O1, O2, O5 och O6 anfaller mot X3, X4 och Mv1."],prog:[],skiss:{layout:"mv_liten",dim:"40\u00d735m",spelare:[{x:8,y:50,roll:"MV"},{x:25,y:20,roll:"O"},{x:25,y:50,roll:"O"},{x:62,y:20,roll:"X"},{x:62,y:50,roll:"X"}],koner:[{x:10,y:10},{x:90,y:10},{x:10,y:90},{x:90,y:90}],pilar:[]},url:""},
