  "ovningar2_044":{id:"ovningar2_044",namn:"Spelövning (mellanstort spel) - kollektiv kontring 2",typ:"Spelövning",skede:"OMANF",kategori:"Omst. → Anfall – Kontring",principer:["Kontra snabbt"],vad:"Kontring",varfor:"Snabbt komma bakom motståndarnas lagdelar och avsluta.",hur:["Löp i maxfart för att passera motståndarnas lagdelar.","Spela bollen framför löpande medspelare."],org:"3 målvakter, 16 utespelare, spelplan 50 x 60 meter med 2 mål, bollar, koner och västar.",steg:["Placera anfallsspelarna i 6 grupper med 2 spelare i varje grupp. 2 backar försvarar vid respektive mål.","Mv1 slår ett inlägg mot Mv2 som fångar bollen och kastar ut den till X1.","X1 passar till X2 som gör tillbakaspel till X3.","X3 spelar bollen i djupled till X4 som löper in bakom motståndarnas backlinje och avslutar mot Mv3.","Om försvarsspelarna bryter skjuter de distansskott.","Övningen fortsätter med inlägg från Mv1 till Mv3."],prog:[],skiss:{spel:[{x:50,y:10,roll:"MV",label:"MV2"},{x:50,y:50,roll:"MV",label:"MV3"},{x:75,y:42,roll:"MV",label:"MV1"},{x:22,y:18,roll:"X",label:"X1"},{x:78,y:18,roll:"X",label:""},{x:32,y:30,roll:"X",label:""},{x:50,y:30,roll:"O",label:""},{x:68,y:30,roll:"O",label:""},{x:35,y:42,roll:"X",label:""},{x:50,y:40,roll:"X",label:"X3"},{x:55,y:45,roll:"O",label:""},{x:38,y:50,roll:"X",label:""},{x:52,y:50,roll:"X",label:"X2"},{x:72,y:48,roll:"X",label:""},{x:78,y:45,roll:"X",label:""}],koner:[],pilar:[{x1:50,y1:50,x2:22,y2:18,stipplad:true},{x1:50,y1:50,x2:78,y2:18,stipplad:true},{x1:52,y1:50,x2:50,y2:10,stipplad:false}],zoner:[50],dim:"50\u00d760m",mal:true,etiketter:[]},url:""},
