  "ovningar2_101":{id:"ovningar2_101",namn:"Spelövning (mellanstort spel) - kollektiv kontring",typ:"Spelövning",skede:"OMANF",kategori:"Omst. → Anfall – Kontring",principer:["Kontra snabbt"],vad:"Kontring",varfor:"Komma till genombrott och göra mål.",hur:["Bollhållaren utmanar.","Snabbt djupledsspel.","Medspelarna gör snabba djupledslöpningar."],org:"2 målvakter, 16 utespelare, spelplan 52 x 40 meter med 2 mål, bollar, koner och västar.",steg:["X1 passar till X2.","X1–X5 anfaller mot O1–O3.","Efter avslutat anfall startar det andra laget på motsvarande sätt med O4 och O5 som forwards. X2 och X5 går ut och X1,","X3 och X4 försvarar tillsammans med Mv2."],prog:[],skiss:{layout:"kontring",dim:"52\u00d740m",spelare:[{x:5,y:50,roll:"MV"},{x:95,y:50,roll:"MV"},{x:20,y:25,roll:"O"},{x:20,y:50,roll:"O"},{x:65,y:25,roll:"X"},{x:65,y:50,roll:"X"},{x:48,y:35,roll:"O",label:"FW"},{x:48,y:65,roll:"O",label:"FW"}],koner:[{x:8,y:8},{x:92,y:8},{x:8,y:92},{x:92,y:92}],pilar:[{x1:20,y1:50,x2:45,y2:38},{x1:45,y1:38,x2:65,y2:28}]},url:""},
  "ovningar2_102":{id:"ovningar2_102",namn:"Spelövning (mellanstort spel) - klassisk kontring",typ:"Spelövning",skede:"OMANF",kategori:"Omst. → Anfall – Kontring",principer:["Kontra snabbt"],vad:"Kontring",varfor:"Snabbt ta sig in med bollen i spelyta 3 genom klassisk kontring.",hur:["Spela framåt direkt efter att ha erövrat bollen.","Löp snabbt i djupled.","Flytta upp."],org:"14 spelare, spelplan 60 x 40 meter, bollar, koner och västar.",steg:["Gör cirka 15 meter djupa målzoner vid kortsidorna.","Spel 7 mot 7 i den centrala delen av spelplanen.","När ett lag erövrar bollen från motståndarna ska laget snabbt sträva efter att spela in bollen i målzonen till en löpande spelare.","Spelaren som tar emot passningen får inte vara i målzonen före bollen.","En spelare ur det försvarande laget får följa med in för att bryta djupledspassningen."],prog:[],skiss:{layout:"kontring",dim:"60\u00d740m",spelare:[{x:20,y:25,roll:"O"},{x:20,y:50,roll:"O"},{x:20,y:75,roll:"O"},{x:35,y:35,roll:"O"},{x:35,y:65,roll:"O"},{x:65,y:25,roll:"X"},{x:65,y:50,roll:"X"},{x:65,y:75,roll:"X"},{x:80,y:35,roll:"X"},{x:80,y:65,roll:"X"},{x:48,y:35,roll:"O",label:"FW"},{x:48,y:65,roll:"O",label:"FW"}],koner:[{x:8,y:8},{x:92,y:8},{x:8,y:92},{x:92,y:92}],pilar:[{x1:20,y1:50,x2:45,y2:38},{x1:45,y1:38,x2:65,y2:28}]},url:""},
