  "ovningar2_118":{id:"ovningar2_118",namn:"Spelövning (mellanstort spel) - indirekt",typ:"Spelövning",skede:"OMFOR",kategori:"Omst. → Försvar – Återerövring",principer:["Återerövring"],vad:"Återerövring av bollen",varfor:"Täcka ytorna bakom lagdelarna.",hur:["Återgå snabbt till utgångspositioner för försvarsspel.","Minimera ytan bakom backlinjen och mellan lagdelarna.","Återerövra bollen."],org:"2 målvakter, 14 utespelare, spelplan 60 x 40 meter med 2 mål, bollar, koner och västar.",steg:["Spel 7 mot 7 med målvakter.","När laget förlorar bollinnehavet ska spelarna direkt inta utgångspositioner för försvarsspel, till exempel 3–3–1."],prog:[],skiss:{layout:"tva_mal",dim:"60\u00d740m",spelare:[{x:8,y:50,roll:"MV"},{x:92,y:50,roll:"MV"},{x:25,y:20,roll:"O"},{x:25,y:50,roll:"O"},{x:62,y:20,roll:"X"},{x:62,y:50,roll:"X"}],koner:[{x:8,y:8},{x:92,y:8},{x:8,y:92},{x:92,y:92}],pilar:[]},url:""},
